import{_ as a}from"./chunks/rescue-shell.BwLPMtHZ.js";import o from"./includes_payloads.md.DXQq0zwk.js";import{o as i,c as l,ae as t,E as n,k as s}from"./chunks/framework.CbfcRfVi.js";const r="/playstation-linux-tutorial/screenshots/internal-drive-conf.png",f=JSON.parse('{"title":"Internal HDD installation","description":"","frontmatter":{"prev":{"text":"Go back to Installation Methods","link":"/installation"},"next":{"text":"Ending","link":"/ending"}},"headers":[],"relativePath":"ps4/internal-installation.md","filePath":"ps4/internal-installation.md","lastUpdated":1777892371000}'),d={name:"ps4/internal-installation.md"},y=Object.assign(d,{setup(c){return(h,e)=>(i(),l("div",null,[e[0]||(e[0]=t('<h1 id="internal-hdd-installation" tabindex="-1">Internal HDD installation <a class="header-anchor" href="#internal-hdd-installation" aria-label="Permalink to &quot;Internal HDD installation&quot;">​</a></h1><p>Here you&#39;ll setup the internal HDD for installation of a Linux distro.</p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>Make sure you are NOT following this on a console with a Baikal southbridge.</p><p>If you proceed, either it won&#39;t boot, or you&#39;ll inevitably corrupt your whole drive and loose all your data!</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>This shit is slow on an HDD. Be careful and prepare your balls for imminent explosion.</p><p>However, if you have swapped your internal HDD for an SSD, this doesn&#39;t apply.</p></div><h2 id="internal-hdd-setup" tabindex="-1">Internal HDD setup <a class="header-anchor" href="#internal-hdd-setup" aria-label="Permalink to &quot;Internal HDD setup&quot;">​</a></h2><p>Check your PS4 storage, as you&#39;ll need to choose the size of the installation. Leave some free space in your console, and remember that the PS4 doesn&#39;t report the space taken internally by Linux!</p><p>FTP to your PS4. Go to the <code>/data/</code> folder, and create the folder <code>/linux/boot/</code> and place your bzImage (and bootargs.txt if you have it) and initramfs in there.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Files sent via FTP can transfer incorrectly, especially if overwritten. In that case, try to move them using a USB drive.</p></div><img src="'+r+'" width="50%"><p>Then, go to <code>/user/system/</code>, create a folder called <code>boot</code>, and paste your distro in there. Remember that it needs to be called <code>psxitarch.tar.gz</code> or <code>xz</code>!</p><p>When installed, you can remove your Linux installation by removing the above files, and the &quot;linux.img&quot; found in <code>/user/home/</code> folder. Just in case you realize I was correct.</p>',11)),n(s(o)),e[1]||(e[1]=t('<h2 id="installation-commands" tabindex="-1">Installation commands <a class="header-anchor" href="#installation-commands" aria-label="Permalink to &quot;Installation commands&quot;">​</a></h2><p>Now that the storage is covered, here comes the moment of truth. You&#39;ll be sent to the Rescue Shell, which will look like this:</p><img src="'+a+'" width="80%"><ul><li>Type <code>install-linux-hdd.sh</code> or <code>linux-install-hdd.sh</code></li><li>Type how much storage you want to use for the installation <ul><li>Check how much free space you have, don&#39;t fill up your drive as the PS4 will only report the used amount of space inside the partition, and not the total partition size!</li><li>If it fails, check your initramfs, or go to the <a href="/playstation-linux-tutorial/issues.html#installation-issues">Installation Issues</a></li></ul></li></ul><p>Hydrate yourself while you wait. It&#39;ll take a while.</p><p>It should already boot into the desktop. If it doesn&#39;t, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resume-boot</span></span></code></pre></div><h2 id="finale" tabindex="-1">Finale <a class="header-anchor" href="#finale" aria-label="Permalink to &quot;Finale&quot;">​</a></h2><p>Go now, conquer the finale. Also, read the post-credit stuff.</p>',9))]))}});export{f as __pageData,y as default};
